type Element_Model (Content : Content_Spec) is record
   case Content is
      when Character_Data | Empty | Anything => null;
      when Element_Ref =>
         Name : Unicode.CES.Byte_Sequence_Access;
      when Any_Of | Sequence =>
         List : Element_Model_Array_Ptr;
      when Repeat =>
         Min : Natural;
         Max : Positive;
         Elem : Element_Model_Ptr;
   end case;
end record;
